ruleSearch.name:
$.title
@js:
bq = `{{$.title}},{{$.authors}},{{$.categories}},{{$.tags}}`;
var key = java.get('key') || '';
pb = `{{Map('屏蔽：')}},${Tag('屏蔽：',key)}`.replace(/^,|,$/g,'');
var containsAny = pb.split(',').some(item => new RegExp(item).test(bq));
(pb !== '' && containsAny) ? '' : result;

ruleToc.preUpdateJs:
var newurl = Get('url');
var burl = java.hexDecodeToString(java.ajax(book.bookUrl));
var turl = java.hexDecodeToString(java.ajax(book.tocUrl));
if (!String(burl).includes(newurl)) {
    burl = String(burl).replace(/.*\/\/[^\/]+/, newurl);
    turl = String(turl).replace(/.*\/\/[^\/]+/, newurl);
    var databurl = `data:;base64,${java.base64Encode(burl)},{"type":"uaabook"}`;
    var dataturl = `data:;base64,${java.base64Encode(turl)},{"type":"uaachapters"}`;
    book.bookUrl = databurl;
    book.tocUrl = dataturl;
    java.refreshTocUrl();
}

ruleToc.nextTocUrl:
